	/* created this endpoint so the success of logging into Spring Security’s default login endpoint won't be contingent on whether Spring Security can 
	 * redirect to '/' after successful authentication. The target endpoint of redirect: in a return statement must support the GET HTTP method b/c the 
	 * redirect prefix typically uses GET requests. */
	@GetMapping("/")
	public void defaultLogin(HttpServletRequest httpRequest, HttpServletResponse httpResponse) throws IOException {
		String authorizationUri = "https://localhost:443/emilefinancialservices/oauth2/authorize?response_type=code&client_id=client&redirect_uri=https://localhost:443/emilefinancialservices/login/oauth2/code/my-client-registration-id&scope=read write"; 
		httpResponse.sendRedirect(authorizationUri); // URI becomes https://localhost:443/emilefinancialservices/login/oauth2/code/my-client-registration-id?code=rKfm_F9akM-wWyWSLg5qP8PbQBfQZ03E_2VTrkSzFnJD0-6MEOjFWaUXe--KVfmUIY3UvclC3lSQibGVAvATrhgL0LGqVlTqJVXcXArPq_SsrfTE39IDFGn63pG7Ad9Qupon upon successful redirect to /login/oauth2/code/my-client-registration-id, in which the authorization code to be exchanged for the token, is dynamically provided for in the URI as query parameter.
//		return "redirect:" + authorizationUri;
	}
